const WeatherCard = ({
  city,
  icon,
  temperature,
  feelsLike,
  condition,
  wind,
  humidity,
  aqi
}) => {

  // ✅ extract AQI safely
  const aqiValue =
    aqi?.["us-epa-index"] ??
    aqi?.air_quality?.["us-epa-index"] ??
    aqi;

  const hasAQI = aqiValue !== undefined && aqiValue !== null;

  return (
    <div className="card">
      <h2>{city}</h2>

      <img src={icon} alt="weather icon" />

      <p>Temperature: {temperature}</p>
      <p>Feels Like: {feelsLike}</p>
      <p>Condition: {condition}</p>
      <p>Wind: {wind}</p>
      <p>Humidity: {humidity}</p>

      {/* ✅ ONLY AQI INDEX */}
      <p>
        AQI: {hasAQI ? aqiValue : "N/A"}
      </p>
    </div>
  );
};

export default WeatherCard;
